description:
A lot of `NOT_FOUND_COLUMN_IN_BLOCK` errors. [Repro](https://fiddle.clickhouse.com/09c5839e-78bd-4b04-b50a-80abe787ceee). Queries used:
```
DROP TABLE IF EXISTS test_replacing_mt;
CREATE TABLE test_replacing_mt(
key Int64,
someCol String,
ver DateTime
) ENGINE = ReplacingMergeTree(ver)
ORDER BY key;
INSERT INTO test_replacing_mt VALUES
(1, 'test1', '2020-01-01'),
(1, 'test2', '2021-01-01'),
(2, 'test3', '2020-06-01'),
(2, 'test4', '2021-06-01');
-- Use version column only in PREWHERE with other columns in SELECT
SELECT key, someCol FROM test_replacing_mt FINAL PREWHERE ver > '2020-01-01' ORDER BY key;
DROP TABLE IF EXISTS test_replacing_mt_with_is_deleted;
CREATE TABLE test_replacing_mt_with_is_deleted(
key Int64,
someCol String,
ver UInt64,
is_deleted UInt8
) ENGINE = ReplacingMergeTree(ver, is_deleted)
ORDER BY key;
INSERT INTO test_replacing_mt_with_is_deleted VALUES
(1, 'test1', 1, 0),
(1, 'test2', 2, 0),
(2, 'test3', 1, 0),
(2, 'test4', 2, 1),
(3, 'test5', 1, 1);
-- Use both version and is_deleted in PREWHERE but not in SELECT
SELECT count() FROM test_replacing_mt_with_is_deleted FINAL PREWHERE ver > 0 AND is_deleted = 0;
-- Use is_deleted in PREWHERE and version in SELECT
SELECT count(ver) FROM test_replacing_mt_with_is_deleted FINAL PREWHERE is_deleted = 0;
-- Use both special columns in PREWHERE, but only data columns in SELECT
SELECT key, someCol FROM test_replacing_mt_with_is_deleted FINAL PREWHERE ver > 0 AND is_deleted = 0 ORDER BY key;
DROP TABLE IF EXISTS test_collapsing_mt;
CREATE TABLE test_collapsing_mt(
key Int64,
someCol String,
sign Int8
) ENGINE = CollapsingMergeTree(sign)
ORDER BY key;
INSERT INTO test_collapsing_mt VALUES
(1, 'test1', 1),
(1, 'test1', -1),
(2, 'test2', 1),
(3, 'test3', 1);
-- Use sign column only in PREWHERE with other columns in SELECT
SELECT key, someCol FROM test_collapsing_mt FINAL PREWHERE sign = 1 ORDER BY key;

